mapper.select:
select rkl.id, rkl.article_id, rkl.user_id, rkl.content, rkl.root_id, rkl.parent_id, rkl.reply_to_user_id, rkl.like_count, rkl.reply_count, rkl.status, rkl.create_time from ( select c.*, row_number() over (partition by c.root_id order by c.create_time asc, c.id asc) as rk from comment c where
#{rootId}
and status != 'HIDDEN' ) as rkl where rk <= #{previewSize} order by rkl.root_id, rkl.create_time asc, rkl.id asc

select id, article_id, user_id, content, root_id, parent_id, reply_to_user_id, like_count, reply_count, status, create_time from comment where article_id = #{articleId} and root_id = #{rootId} and status != 'HIDDEN'
and ( #{lastCreatedAt} is null or create_time > #{lastCreatedAt} or (create_time = #{lastCreatedAt} and id > #{lastId}) )
order by create_time asc, id asc limit #{size}

select article_id as articleId, count(*) as commentCount from comment where article_id in
#{articleId}
and status!='HIDDEN' group by article_id
